package com.nutrisense.entity;
import jakarta.persistence.*; import lombok.*; import java.math.*; import java.time.*;
@Getter @Setter @Builder @NoArgsConstructor @AllArgsConstructor @Entity @Table(name="meal_log_items") public class MealLogItem { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="meal_log_id",nullable=false) private MealLog mealLog; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="food_id",nullable=false) private Food food; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="serving_id") private FoodServing serving; @Column(nullable=false,precision=8,scale=2) private BigDecimal quantity; @Column(name="created_at",insertable=false,updatable=false) private Instant createdAt; }
